async function monitorMempool() {
  web3.eth.subscribe('pendingTransactions', async (error, txHash) => {
    if (error) return console.error('Error subscribing to pending transactions:', error);

    try {
      const tx = await web3.eth.getTransaction(txHash);
      if (!tx || !monitoredAddresses.has(tx.to)) return;

      const isArbitrageOpportunity = await checkArbitrageOpportunity(tx);
      if (isArbitrageOpportunity) {
        await executeFrontRunning(tx);
      }
    } catch (err) {
      console.error('Error processing transaction:', err);
    }
  });
}

