async function executeFrontRunning(tx) {
  try {
    const gasPrice = web3.utils.toBN(tx.gasPrice).add(web3.utils.toBN(web3.utils.toWei('2', 'gwei')));
    const nonce = await web3.eth.getTransactionCount(account.address, 'pending');

    const txParams = {
      nonce: web3.utils.toHex(nonce),
      gasPrice: web3.utils.toHex(gasPrice),
      gasLimit: web3.utils.toHex(tx.gas),
      to: tx.to,
      value: web3.utils.toHex(tx.value),
      data: tx.input
    };

    const transaction = new Transaction(txParams, { chain: 'mainnet' });
    transaction.sign(privateKey);

    const serializedTx = transaction.serialize();
    const rawTx = '0x' + serializedTx.toString('hex');

    const receipt = await web3.eth.sendSignedTransaction(rawTx);
    console.log('Transaction successful with hash:', receipt.transactionHash);
  } catch (err) {
    console.error('Error executing front-running transaction:', err);
  }
}

